export class GlpiFormItemAdvancedConfig{static instance=null;constructor(){if(GlpiFormItemAdvancedConfig.instance!==null){return GlpiFormItemAdvancedConfig.instance}this.registerEventListeners();GlpiFormItemAdvancedConfig.instance=this}findContainer(i){const e=i.find(`[data-glpi-form-editor-item-dropdown-advanced-configuration]`);return e.length>0?e:null}registerEventListeners(){$(document).on("glpi-form-editor-question-sub-type-changed",(i,e,t)=>{if(e.find('[data-glpi-form-editor-original-name="type"], [name="type"]').length===0||e.find('[data-glpi-form-editor-original-name="type"], [name="type"]').val()!=="Glpi\\Form\\QuestionType\\QuestionTypeItem"){return}const n=this.findContainer(e);if(!n){return}this.updateAdvancedConfigVisibility(n,t)})}updateAdvancedConfigVisibility(i,e){const t=i.closest("[data-glpi-form-editor-advanced-question-configuration]").parents("[data-glpi-form-editor-question-extra-details]");if(e==="Entity"){t.show()}else{t.hide()}}}